const e = $json;
const wf = e.workflow?.name || 'unknown workflow';
const node = e.execution?.lastNodeExecuted || 'unknown node';
const msg = e.execution?.error?.message || 'no message';
const url = e.execution?.url || '';
return [{ json: {
  text: `❌ WORKFLOW FAILED\nWorkflow: ${wf}\nNode: ${node}\nError: ${String(msg).slice(0, 500)}${url ? '\nExecution: ' + url : ''}`
} }];
